addEventListener('fetch', event => {
  event.respondWith(handle(event.request))
})

async function handle(request) {
  // Simple edge rate-limit example (pseudocode for a Worker)
  const ip = request.headers.get('CF-Connecting-IP') || 'unknown'
  const key = `rl:${ip}`
  const count = await RATE_LIMIT_STORE.get(key) || 0
  if (count > 100) {
    return new Response('Too many requests', { status: 429 })
  }
  await RATE_LIMIT_STORE.put(key, Number(count) + 1, { expirationTtl: 1 })

  // Serve cached response where safe
  const cache = caches.default
  const cached = await cache.match(request)
  if (cached) return cached

  // Otherwise forward to origin (Edge / Origin Shield will handle fetching)
  const resp = await fetch(request)
  // Cache short-lived responses for the attack window
  if (shouldCache(request)) {
    event.waitUntil(cache.put(request, resp.clone()))
  }
  return resp
}
